import { type ChxInlinePluginRegistration, type ColumnDefinition, type ResolvedChxConfig, type SchemaDefinition } from '@chkit/core';
export interface TypegenPluginOptions {
    outFile?: string;
    emitZod?: boolean;
    tableNameStyle?: 'pascal' | 'camel' | 'raw';
    bigintMode?: 'string' | 'bigint';
    includeViews?: boolean;
    runOnGenerate?: boolean;
    failOnUnsupportedType?: boolean;
}
export interface TypegenPluginCommandContext {
    args: string[];
    jsonMode: boolean;
    options: Record<string, unknown>;
    config: ResolvedChxConfig;
    configPath: string;
    print: (value: unknown) => void;
}
export interface TypegenPlugin {
    manifest: {
        name: 'typegen';
        apiVersion: 1;
        version?: string;
    };
    commands: Array<{
        name: 'typegen';
        description: string;
        run: (context: TypegenPluginCommandContext) => undefined | number | Promise<undefined | number>;
    }>;
    hooks?: {
        onConfigLoaded?: (context: {
            command: string;
            configPath: string;
            options: Record<string, unknown>;
        }) => void;
        onCheck?: (context: TypegenPluginCheckContext) => TypegenPluginCheckResult | undefined | Promise<TypegenPluginCheckResult | undefined>;
        onCheckReport?: (context: {
            result: TypegenPluginCheckResult;
            print: (line: string) => void;
        }) => void | Promise<void>;
    };
}
export interface TypegenFinding {
    code: 'typegen_unsupported_type' | 'typegen_stale_output' | 'typegen_missing_output';
    message: string;
    severity: 'warn' | 'error';
    path?: string;
}
export interface MapColumnTypeResult {
    tsType: string;
    zodType: string;
    nullable: boolean;
    finding?: TypegenFinding;
}
export interface GenerateTypeArtifactsInput {
    definitions: SchemaDefinition[];
    options?: TypegenPluginOptions;
    now?: Date;
    toolVersion?: string;
}
export interface GenerateTypeArtifactsOutput {
    content: string;
    outFile: string;
    declarationCount: number;
    findings: TypegenFinding[];
}
export interface TypegenPluginCheckContext {
    command: 'check';
    config: ResolvedChxConfig;
    configPath: string;
    jsonMode: boolean;
    options: Record<string, unknown>;
}
export type TypegenPluginRegistration = ChxInlinePluginRegistration<TypegenPlugin, TypegenPluginOptions>;
export interface TypegenPluginCheckResult {
    plugin: string;
    evaluated: boolean;
    ok: boolean;
    findings: Array<{
        code: string;
        message: string;
        severity: 'info' | 'warn' | 'error';
        metadata?: Record<string, unknown>;
    }>;
    metadata?: Record<string, unknown>;
}
export declare function normalizeTypegenOptions(options?: TypegenPluginOptions): Required<TypegenPluginOptions>;
export declare function mapColumnType(input: {
    column: ColumnDefinition;
    path: string;
}, options: Pick<Required<TypegenPluginOptions>, 'bigintMode' | 'failOnUnsupportedType'>): MapColumnTypeResult;
export declare function generateTypeArtifacts(input: GenerateTypeArtifactsInput): GenerateTypeArtifactsOutput;
export declare function isRunOnGenerateEnabled(baseOptions: Required<TypegenPluginOptions>, runtimeOptions: Record<string, unknown>): boolean;
export declare function createTypegenPlugin(options?: TypegenPluginOptions): TypegenPlugin;
export declare function typegen(options?: TypegenPluginOptions): TypegenPluginRegistration;
//# sourceMappingURL=index.d.ts.map

