     1→import { mkdir, readFile, rename, writeFile } from 'node:fs/promises';
     2→import { dirname, join, resolve } from 'node:path';
     3→import { canonicalizeDefinitions, loadSchemaDefinitions, } from '@chkit/core';
     4→const DEFAULT_OPTIONS = {
     5→    outFile: './src/generated/chkit-types.ts',
     6→    emitZod: false,
     7→    tableNameStyle: 'pascal',
     8→    bigintMode: 'string',
     9→    includeViews: false,
    10→    runOnGenerate: true,
    11→    failOnUnsupportedType: true,
    12→};
    13→const LARGE_INTEGER_TYPES = new Set([
    14→    'Int64',
    15→    'UInt64',
    16→    'Int128',
    17→    'UInt128',
    18→    'Int256',
    19→    'UInt256',
    20→]);
    21→const NUMBER_TYPES = new Set([
    22→    'Int8',
    23→    'Int16',
    24→    'Int32',
    25→    'UInt8',
    26→    'UInt16',
    27→    'UInt32',
    28→    'Float32',
    29→    'Float64',
    30→    'BFloat16',
    31→]);
    32→const STRING_TYPES = new Set([
    33→    'String',
    34→    'FixedString',
    35→    'Date',
    36→    'Date32',
    37→    'DateTime',
    38→    'DateTime64',
    39→    'UUID',
    40→    'IPv4',
    41→    'IPv6',
    42→    'Enum',
    43→    'Enum8',
    44→    'Enum16',
    45→    'Decimal',
    46→    'Decimal32',
    47→    'Decimal64',
    48→    'Decimal128',
    49→    'Decimal256',
    50→]);
    51→const BOOLEAN_TYPES = new Set(['Bool', 'Boolean']);
    52→class TypegenConfigError extends Error {
    53→    constructor(message) {
    54→        super(message);
    55→        this.name = 'TypegenConfigError';
    56→    }
    57→}
    58→class UnsupportedTypeError extends Error {
    59→    path;
    60→    sourceType;
    61→    constructor(path, sourceType) {
    62→        super(`Unsupported column type "${sourceType}" at ${path}. Set failOnUnsupportedType=false to emit unknown.`);
    63→        this.name = 'UnsupportedTypeError';
    64→        this.path = path;
    65→        this.sourceType = sourceType;
    66→    }
    67→}
    68→function parseBooleanOption(options, key) {
    69→    const value = options[key];
    70→    if (value === undefined)
    71→        return undefined;
    72→    if (typeof value === 'boolean')
    73→        return value;
    74→    throw new TypegenConfigError(`Invalid plugin option "${key}". Expected boolean.`);
    75→}
    76→function parseStringOption(options, key) {
    77→    const value = options[key];
    78→    if (value === undefined)
    79→        return undefined;
    80→    if (typeof value === 'string' && value.length > 0)
    81→        return value;
    82→    throw new TypegenConfigError(`Invalid plugin option "${key}". Expected non-empty string.`);
    83→}
    84→function normalizeRuntimeOptions(options) {
    85→    const rawTableNameStyle = options.tableNameStyle;
    86→    if (rawTableNameStyle !== undefined &&
    87→        rawTableNameStyle !== 'pascal' &&
    88→        rawTableNameStyle !== 'camel' &&
    89→        rawTableNameStyle !== 'raw') {
    90→        throw new TypegenConfigError('Invalid plugin option "tableNameStyle". Expected one of: pascal, camel, raw.');
    91→    }
    92→    const rawBigintMode = options.bigintMode;
    93→    if (rawBigintMode !== undefined && rawBigintMode !== 'string' && rawBigintMode !== 'bigint') {
    94→        throw new TypegenConfigError('Invalid plugin option "bigintMode". Expected one of: string, bigint.');
    95→    }
    96→    const normalized = {};
    97→    const outFile = parseStringOption(options, 'outFile');
    98→    const emitZod = parseBooleanOption(options, 'emitZod');
    99→    const includeViews = parseBooleanOption(options, 'includeViews');
   100→    const runOnGenerate = parseBooleanOption(options, 'runOnGenerate');
   101→    const failOnUnsupportedType = parseBooleanOption(options, 'failOnUnsupportedType');
   102→    if (outFile !== undefined)
   103→        normalized.outFile = outFile;
   104→    if (emitZod !== undefined)
   105→        normalized.emitZod = emitZod;
   106→    if (rawTableNameStyle !== undefined)
   107→        normalized.tableNameStyle = rawTableNameStyle;
   108→    if (rawBigintMode !== undefined)
   109→        normalized.bigintMode = rawBigintMode;
   110→    if (includeViews !== undefined)
   111→        normalized.includeViews = includeViews;
   112→    if (runOnGenerate !== undefined)
   113→        normalized.runOnGenerate = runOnGenerate;
   114→    if (failOnUnsupportedType !== undefined)
   115→        normalized.failOnUnsupportedType = failOnUnsupportedType;
   116→    return normalized;
   117→}
   118→export function normalizeTypegenOptions(options = {}) {
   119→    return {
   120→        ...DEFAULT_OPTIONS,
   121→        ...options,
   122→    };
   123→}
   124→function toWords(input) {
   125→    return input
   126→        .split(/[^a-zA-Z0-9]+/)
   127→        .map((part) => part.trim())
   128→        .filter((part) => part.length > 0);
   129→}
   130→function pascalCase(input) {
   131→    const words = toWords(input);
   132→    if (words.length === 0)
   133→        return 'Item';
   134→    return words.map((part) => part[0]?.toUpperCase() + part.slice(1)).join('');
   135→}
   136→function camelCase(input) {
   137→    const words = toWords(input);
   138→    if (words.length === 0)
   139→        return 'item';
   140→    const [head, ...tail] = words;
   141→    return `${head?.toLowerCase() ?? 'item'}${tail
   142→        .map((part) => part[0]?.toUpperCase() + part.slice(1))
   143→        .join('')}`;
   144→}
   145→function rawCase(input) {
   146→    const sanitized = input.replace(/[^a-zA-Z0-9_]/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '');
   147→    return sanitized.length > 0 ? sanitized : 'item';
   148→}
   149→function isValidIdentifier(input) {
   150→    return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(input);
   151→}
   152→function renderPropertyName(name) {
   153→    if (isValidIdentifier(name))
   154→        return name;
   155→    return JSON.stringify(name);
   156→}
   157→function baseRowTypeName(definition, style) {
   158→    const combined = `${definition.database}_${definition.name}`;
   159→    if (style === 'raw') {
   160→        const candidate = `${rawCase(combined)}_row`;
   161→        return isValidIdentifier(candidate) ? candidate : `_${candidate}`;
   162→    }
   163→    if (style === 'camel') {
   164→        return `${camelCase(combined)}Row`;
   165→    }
   166→    return `${pascalCase(combined)}Row`;
   167→}
   168→function resolveTableNames(definitions, style) {
   169→    const baseNames = definitions.map((definition) => ({
   170→        definition,
   171→        base: baseRowTypeName(definition, style),
   172→    }));
   173→    const counts = new Map();
   174→    return baseNames.map((item) => {
   175→        const seen = counts.get(item.base) ?? 0;
   176→        const nextSeen = seen + 1;
   177→        counts.set(item.base, nextSeen);
   178→        return {
   179→            definition: item.definition,
   180→            interfaceName: nextSeen === 1 ? item.base : `${item.base}_${nextSeen}`,
   181→        };
   182→    });
   183→}
   184→function splitTopLevelArgs(input) {
   185→    const args = [];
   186→    let depth = 0;
   187→    let start = 0;
   188→    for (let i = 0; i < input.length; i++) {
   189→        const ch = input[i];
   190→        if (ch === '(')
   191→            depth++;
   192→        else if (ch === ')')
   193→            depth--;
   194→        else if (ch === ',' && depth === 0) {
   195→            args.push(input.slice(start, i).trim());
   196→            start = i + 1;
   197→        }
   198→    }
   199→    const last = input.slice(start).trim();
   200→    if (last.length > 0)
   201→        args.push(last);
   202→    return args;
   203→}
   204→function parseClickHouseType(typeStr) {
   205→    const trimmed = typeStr.trim();
   206→    const parenIndex = trimmed.indexOf('(');
   207→    if (parenIndex < 0)
   208→        return { base: trimmed, args: [] };
   209→    const base = trimmed.slice(0, parenIndex);
   210→    const closingParen = trimmed.lastIndexOf(')');
   211→    if (closingParen <= parenIndex)
   212→        return { base: trimmed, args: [] };
   213→    const inner = trimmed.slice(parenIndex + 1, closingParen);
   214→    if (inner.trim().length === 0)
   215→        return { base, args: [] };
   216→    return { base, args: splitTopLevelArgs(inner) };
   217→}
   218→function mapScalarType(base, bigintMode) {
   219→    if (STRING_TYPES.has(base))
   220→        return 'string';
   221→    if (BOOLEAN_TYPES.has(base))
   222→        return 'boolean';
   223→    if (NUMBER_TYPES.has(base))
   224→        return 'number';
   225→    if (LARGE_INTEGER_TYPES.has(base))
   226→        return bigintMode;
   227→    return null;
   228→}
   229→function scalarToZod(mapped) {
   230→    if (mapped === 'string')
   231→        return 'z.string()';
   232→    if (mapped === 'number')
   233→        return 'z.number()';
   234→    if (mapped === 'boolean')
   235→        return 'z.boolean()';
   236→    if (mapped === 'bigint')
   237→        return 'z.bigint()';
   238→    return 'z.unknown()';
   239→}
   240→function resolveInnerType(typeStr, bigintMode) {
   241→    const parsed = parseClickHouseType(typeStr);
   242→    const scalar = mapScalarType(parsed.base, bigintMode);
   243→    if (scalar)
   244→        return { tsType: scalar, zodType: scalarToZod(scalar) };
   245→    switch (parsed.base) {
   246→        case 'Nullable': {
   247→            const arg = parsed.args[0];
   248→            if (!arg)
   249→                return null;
   250→            const inner = resolveInnerType(arg, bigintMode);
   251→            if (!inner)
   252→                return null;
   253→            return { tsType: `${inner.tsType} | null`, zodType: `${inner.zodType}.nullable()` };
   254→        }
   255→        case 'LowCardinality': {
   256→            const arg = parsed.args[0];
   257→            if (!arg)
   258→                return null;
